class RodCuttingAlgorithm
{
	public int rodcut(int p[],int n)
	{
		int r[]=new int[n];
		for(int i=0;i<n;i++)
		{
			r[i]=Integer.MIN_VALUE;
		}
		return calculating(p,r,n); 
	}
	public int calculating(int p[],int r[],int n)
	{
		int q;
		if(n==0)
		{
			return 0;
		}
		if(r[n-1]>=0)
		{
			return r[n-1];
		}
		else
		{
			int i;
			q=Integer.MIN_VALUE;
			for(i=0;i<n;i++)
			{
				q=max(q,p[i]+calculating(p,r,n-i-1));
			}
			r[n-1]=q;
			return q;
		}


